532	func truncateBytes(s string, limit int) string {
533		if limit <= 0 || len(s) <= limit {
534			return s
535		}
536		const markerFmt = "\n…[truncated, %d bytes]\n"
537		marker := fmt.Sprintf(markerFmt, len(s))
538		if len(marker) >= limit {
539			return s[:limit]
540		}
541		head := (limit - len(marker)) / 2
542		tail := limit - len(marker) - head
543		return s[:head] + marker + s[len(s)-tail:]
544	}
