// applyRepairExhaustionEscalation handles the inter-attempt escalation path
// after a candidate-cycle repair loop exhausts RepairMaxCycles. When the
// escalation ladder has a higher tier, it sets TriageTierHintKey to the next
// floor so the next attempt runs at a stronger model (ADR-024 P2). When the
// ladder is exhausted, the bead parks to proposed for operator attention.
func applyRepairExhaustionEscalation(store ExecuteBeadLoopStore, beadID, actor string, actualPower int, nextFloorFn func(int) (int, error)) error {
	if nextFloorFn != nil {
		nextFloor, err := nextFloorFn(actualPower)
		if err != nil {
			return store.ParkToProposed(beadID, bead.ParkRepairCycleExhausted, func(b *bead.Bead) {
				ensureBeadExtra(b)
				clearSmartRetryMetadata(b)
			})
		}
		return store.UpdateWithLifecycleStatus(beadID, bead.StatusOpen, bead.LifecycleTransitionOptions{
			Reason: "repair cycles exhausted; escalating implementer to stronger model tier",
			Actor:  actor,
			Source: "ddx agent execute-loop",
		}, func(b *bead.Bead) error {
			ensureBeadExtra(b)
			b.Extra[TriageTierHintKey] = nextFloor
			return nil
		})
	}
	return store.ParkToProposed(beadID, bead.ParkRepairCycleExhausted, func(b *bead.Bead) {
		ensureBeadExtra(b)
		clearSmartRetryMetadata(b)
	})
}

