package agent

import (
	"context"
	"fmt"
	"testing"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// TestReviewBlock_EscalatesImplementerOnRepairExhaustion verifies that when
// the candidate-cycle coordinator exhausts RepairMaxCycles (returning
// repair-cycle-exhausted), the execute-bead loop bumps the implementer
// MinPower by exactly one ladder step via TriageTierHintKey instead of
// parking the bead to proposed.
func TestReviewBlock_EscalatesImplementerOnRepairExhaustion(t *testing.T) {
	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init())

	b := &bead.Bead{ID: "ddx-repairesc-001", Title: "Repair exhaustion escalation"}
	require.NoError(t, store.Create(b))

	// Two-rung ladder: 70 → 90.
	nextFloor := func(actualPower int) (int, error) {
		if actualPower < 90 {
			return 90, nil
		}
		return 0, fmt.Errorf("ladder exhausted")
	}

	worker := &ExecuteBeadWorker{
		Store:               store,
		EscalationNextFloor: nextFloor,
		Executor: ExecuteBeadExecutorFunc(func(_ context.Context, beadID string) (ExecuteBeadReport, error) {
			return ExecuteBeadReport{
				BeadID:      beadID,
				Status:      ExecuteBeadStatusRepairCycleExhausted,
				ActualPower: 70,
			}, nil
		}),
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	_, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{Once: true})
	require.NoError(t, err)

	got, err := store.Get(b.ID)
	require.NoError(t, err)
	assert.Equal(t, bead.StatusOpen, got.Status,
		"repair-cycle-exhausted at non-top tier must keep bead open for escalated retry")
	// After JSON round-trip Extra values come back as float64.
	assert.Equal(t, float64(90), got.Extra[TriageTierHintKey],
		"repair-cycle-exhausted at power 70 must set tier hint to next step (90)")
}

// TestReviewBlock_StillFailsAtTopTier_ParkProposed verifies that when the
// repair cycle exhausts and the escalation ladder is already at the top tier
// (EscalationNextFloor returns an error), the bead is parked to proposed for
// operator attention rather than retried.
func TestReviewBlock_StillFailsAtTopTier_ParkProposed(t *testing.T) {
	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init())

	b := &bead.Bead{ID: "ddx-repairesc-002", Title: "Repair exhaustion at top tier"}
	require.NoError(t, store.Create(b))

	worker := &ExecuteBeadWorker{
		Store: store,
		// Ladder exhausted: already at top tier.
		EscalationNextFloor: func(_ int) (int, error) {
			return 0, fmt.Errorf("ladder exhausted")
		},
		Executor: ExecuteBeadExecutorFunc(func(_ context.Context, beadID string) (ExecuteBeadReport, error) {
			return ExecuteBeadReport{
				BeadID:      beadID,
				Status:      ExecuteBeadStatusRepairCycleExhausted,
				ActualPower: 90,
			}, nil
		}),
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	_, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{Once: true})
	require.NoError(t, err)

	got, err := store.Get(b.ID)
	require.NoError(t, err)
	assert.Equal(t, bead.StatusProposed, got.Status,
		"repair-cycle-exhausted at top tier must park bead to proposed for operator attention")
	assert.NotContains(t, got.Extra, TriageTierHintKey,
		"proposed bead must not have a tier hint")
}

// TestReviewBlock_NonFixableClassification_DoesNotEscalate verifies that a
// plain review_block verdict (non-fixable classification: spec_gap or
// too_large) does NOT trigger the repair-exhaustion escalation path. The bead
// must not receive a TriageTierHintKey — it remains open for normal retry or
// operator handling, without consuming the escalation ladder.
func TestReviewBlock_NonFixableClassification_DoesNotEscalate(t *testing.T) {
	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init())

	b := &bead.Bead{ID: "ddx-repairesc-003", Title: "Non-fixable review block"}
	require.NoError(t, store.Create(b))

	escalationCalled := false
	worker := &ExecuteBeadWorker{
		Store: store,
		EscalationNextFloor: func(actualPower int) (int, error) {
			escalationCalled = true
			return 90, nil
		},
		Executor: ExecuteBeadExecutorFunc(func(_ context.Context, beadID string) (ExecuteBeadReport, error) {
			// Non-fixable review block: spec_gap classification — NOT repair-cycle-exhausted.
			return ExecuteBeadReport{
				BeadID:        beadID,
				Status:        ExecuteBeadStatusReviewBlock,
				OutcomeReason: "spec_gap",
				ActualPower:   70,
			}, nil
		}),
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	_, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{Once: true})
	require.NoError(t, err)

	got, err := store.Get(b.ID)
	require.NoError(t, err)
	assert.False(t, escalationCalled,
		"EscalationNextFloor must not be called for non-fixable review_block")
	assert.NotContains(t, got.Extra, TriageTierHintKey,
		"non-fixable review_block must not set a tier hint")
}

